phase1.code:
public class StringsExample {
    public static void main(String[] args) {
        String str1 = "Hello";
        String str2 = "World";

        // String concatenation
        String combined = str1 + " " + str2 + "!";
        System.out.println("Concatenated: " + combined);

        // Common String methods
        String text = "  Java Programming  ";
        System.out.println("Length: " + text.length());
        System.out.println("Trimmed: '" + text.trim() + "'");
        System.out.println("Uppercase: " + text.toUpperCase());
        System.out.println("Lowercase: " + text.toLowerCase());
        System.out.println("Contains 'Java'? " + text.contains("Java"));
        System.out.println("Character at index 6: " + text.charAt(6));
        System.out.println("Substring (6 to 10): '" + text.substring(6, 10) + "'");

        // String comparison
        String a = "Hello";
        String b = "Hello";
        String c = new String("Hello");

        System.out.println("a == b? " + (a == b));  // true (same reference)
        System.out.println("a == c? " + (a == c));  // false (different objects)
        System.out.println("a.equals(c)? " + a.equals(c));  // true (same content)

        // Strings are immutable!
        String original = "Java";
        String modified = original.toUpperCase();
        System.out.println("Original: " + original);  // Still "Java"
        System.out.println("Modified: " + modified);  // "JAVA"
    }
}

